import React from "react";
import { Link } from "react-router-dom";

const Navbar = () => {
    return (
        <nav className="navbar navbar-expand-lg d-none d-md-block">
            <div className="container">
                <Link className="navbar-brand" to="/">
                    <img src="/images/logo.png" width="50px" alt="" /> <b>Sim Flights Tracker</b>
                </Link>
            <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#main_nav" aria-controls="main_nav" aria-expanded="false" aria-label="Toggle navigation">
                <span className="navbar-toggler-icon"></span>
            </button>
            <div className="collapse navbar-collapse" id="main_nav">
                <ul className="navbar-nav ms-auto mb-2 mb-lg-0">
                <li className="nav-item">
                    <a  rel="noopener noreferrer" className="nav-link" href="//play.google.com/store/apps/details?id=za.co.simflightstracker.www" target="_blank">Play Store</a>
                </li>
                <li className="nav-item">
                    <a rel="noopener noreferrer" className="nav-link" href="//apps.apple.com/us/app/sim-flights-tracker/id1594401428" target="_blank">App Store</a>
                </li>
                <li className="nav-item">
                    <a rel="noopener noreferrer" className="nav-link" href="//galaxy.store/simft" target="_blank">Galaxy Store</a>
                </li>
                <li className="nav-item" style={{borderLeft:"1px solid #aaa5"}}>
                    <Link className="nav-link" to="/privacy">Privacy Policy</Link>
                </li>
                <li className="nav-item" style={{borderLeft:"1px solid #aaa5"}}>
                    <a rel="noopener noreferrer" className="nav-link" href="//github.com/Node-Ninja" target="_blank">  <i className="devicon-github-original"></i> &nbsp; Node-Ninja</a>
                </li>
                </ul>
            </div>
            </div>
        </nav>
    );
}

export default Navbar;